mapper.select:
SELECT a.*, u.nickname as author_name, c.category_name FROM article a LEFT JOIN user u ON a.author_id = u.id LEFT JOIN category c ON a.category_id = c.id WHERE a.deleted = 0
AND a.title LIKE CONCAT('%', #{title}, '%')
AND a.category_id = #{categoryId}
AND a.author_id = #{authorId}
AND a.status = #{status}
ORDER BY a.is_top DESC, a.publish_time DESC
